import React, { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import Login from './pages/Login';
import Register from './pages/Register';
import AdminDashboard from './dashboards/AdminDashboard';
import DoctorDashboard from './dashboards/DoctorDashboard';
import PatientDashboard from './dashboards/PatientDashboard';
import './styles/auth.css';

const PrivateRoute = ({ children, requiredRole }) => {
    const [isAuthenticated, setIsAuthenticated] = useState(null);
    const [userRole, setUserRole] = useState(null);

    useEffect(() => {
        const token = localStorage.getItem('access_token');
        const user = JSON.parse(localStorage.getItem('user') || 'null');
        
        if (token && user) {
            setIsAuthenticated(true);
            setUserRole(user.role);
        } else {
            setIsAuthenticated(false);
        }
    }, []);

    if (isAuthenticated === null) {
        return React.createElement('div', { style: { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' } }, 'Loading...');
    }

    if (!isAuthenticated) {
        return React.createElement(Navigate, { to: '/login' });
    }

    if (requiredRole && userRole !== requiredRole) {
        return React.createElement(Navigate, { to: '/login' });
    }

    return children;
};

function App() {
    return React.createElement(
        BrowserRouter,
        null,
        React.createElement(
            Routes,
            null,
            React.createElement(Route, { path: '/login', element: React.createElement(Login) }),
            React.createElement(Route, { path: '/register', element: React.createElement(Register) }),
            React.createElement(Route, {
                path: '/admin/dashboard/*',
                element: React.createElement(
                    PrivateRoute,
                    { requiredRole: 'admin' },
                    React.createElement(AdminDashboard)
                ),
            }),
            React.createElement(Route, {
                path: '/doctor/dashboard/*',
                element: React.createElement(
                    PrivateRoute,
                    { requiredRole: 'doctor' },
                    React.createElement(DoctorDashboard)
                ),
            }),
            React.createElement(Route, {
                path: '/patient/dashboard/*',
                element: React.createElement(
                    PrivateRoute,
                    { requiredRole: 'patient' },
                    React.createElement(PatientDashboard)
                ),
            }),
            React.createElement(Route, { path: '/', element: React.createElement(Navigate, { to: '/login' }) })
        )
    );
}

export default App;
